function BatchPoller({
  batchRunId,
  listStatus,
  onStatusChange,
  onTerminal,
}: {
  batchRunId: string;
  listStatus: string;
  onStatusChange: () => void;
  onTerminal: (status: string) => void;
}) {
  const queryClient = useQueryClient();
  const { data } = useBatchRunStatus(batchRunId);
  const lastNotifiedStatus = useRef<string | null>(null);
  const status = data?.status?.toLowerCase();
  const normalizedListStatus = listStatus?.toLowerCase();

  useEffect(() => {
    if (!status || status === lastNotifiedStatus.current) {
      return;
    }

    lastNotifiedStatus.current = status;
    const terminal =
      status === "success" || status === "failed" || status === "completed" || status === "failure";

    if (terminal && data) {
      onTerminal(data.status);
      queryClient.invalidateQueries({ queryKey: ["batch", "status", batchRunId] });
      return;
    }

    if (status !== normalizedListStatus) {
      onStatusChange();
    }
  }, [status, normalizedListStatus, data, onTerminal, onStatusChange, queryClient, batchRunId]);

  return null;
}

