export function useRetryBatch() {
  const qc = useQueryClient();
  return useMutation({
    mutationKey: ["batch", "retry"],
    mutationFn: async (args: RetryBatchArgs) => {
      if (!args.accessToken) throw new Error("Missing access token");
      const res = await fetcher(apiUrl(`/batch/${args.batchRunId}/retry`), {
        method: "POST",
        headers: {
          Authorization: `Bearer ${args.accessToken}`,
        },
      });
      if (!res.ok) {
        const body = await res.json().catch(() => ({}));
        throw new Error(body.error || `Failed to retry batch (${res.status})`);
      }
      return res.json();
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["batch", "list"] });
    },
  });
}

