"use client";

import { useMemo, useState, useEffect, useCallback } from "react";
import { format } from "date-fns";
import { Download, File as FileIcon, Archive, ChevronLeft, ChevronRight, X, Play } from "lucide-react";

import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { BatchListItem, useBatchRunStatus } from "@/lib/api/batch";
import { Button } from "@/components/ui/button";

interface BatchDetailDialogProps {
  batchId: string | null;
  batchData: BatchListItem | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function BatchDetailDialog({ batchId, batchData, open, onOpenChange }: BatchDetailDialogProps) {
  // We use the polling hook. It polls if status is not terminal.
  const { data: detailData, isLoading } = useBatchRunStatus(batchId);

  // Merge metadata from the list view (if detailData hasn't loaded or is missing some fields)
  const name = detailData?.batch_name || batchData?.batch_name || "Unknown Batch";
  const pipeline = detailData?.pipeline_name || batchData?.pipeline_name || "Unknown Pipeline";
  const overallStatus = detailData?.status || batchData?.status || "unknown";
  const createdAt = detailData?.created_at || batchData?.created_at;
  const archiveUrl = detailData?.archive_url || batchData?.archive_url;

  // Sort rows ascending by index
  const sortedRows = useMemo(() => {
    const rowResults = detailData?.row_results || [];
    return [...rowResults].sort((a, b) => a.row_index - b.row_index);
  }, [detailData?.row_results]);

  const isProcessing = ["processing", "queued", "pending"].includes(overallStatus.toLowerCase());

  // Preview state now stores the whole array of URLs and the current index to enable navigation
  const [previewImages, setPreviewImages] = useState<string[]>([]);
  const [previewIndex, setPreviewIndex] = useState<number>(0);
  const [imageMeta, setImageMeta] = useState<{ width?: number; height?: number; size?: number; loading?: boolean }>({});

  const isPreviewOpen = previewImages.length > 0;

  const navigatePreview = useCallback((direction: 'prev' | 'next') => {
    if (previewImages.length === 0) return;
    setPreviewIndex((current) => {
      if (direction === 'prev') return current === 0 ? previewImages.length - 1 : current - 1;
      return current === previewImages.length - 1 ? 0 : current + 1;
    });
  }, [previewImages.length]);

  // Fetch image metadata when preview changes
  useEffect(() => {
    if (!isPreviewOpen || !previewImages[previewIndex]) return;

    let isMounted = true;
    const url = previewImages[previewIndex];
    setImageMeta({ loading: true });

    // Fetch size using a HEAD request
    fetch(url, { method: "HEAD" })
      .then(res => {
        const contentLength = res.headers.get("Content-Length");
        if (contentLength && isMounted) {
          setImageMeta(prev => ({ ...prev, size: parseInt(contentLength, 10) }));
        }
      })
      .catch(() => {
        // silently ignore HEAD request errors (like CORS limits)
      });

    // Fetch dimensions — use Image for images, video element for videos
    if (isVideoUrl(url)) {
      const vid = document.createElement('video');
      vid.onloadedmetadata = () => {
        if (isMounted) {
          setImageMeta(prev => ({ ...prev, width: vid.videoWidth, height: vid.videoHeight, loading: false }));
        }
      };
      vid.onerror = () => {
        if (isMounted) setImageMeta(prev => ({ ...prev, loading: false }));
      };
      vid.src = url;
    } else {
      const img = new Image();
      img.onload = () => {
        if (isMounted) {
          setImageMeta(prev => ({ ...prev, width: img.naturalWidth, height: img.naturalHeight, loading: false }));
        }
      };
      img.onerror = () => {
        if (isMounted) setImageMeta(prev => ({ ...prev, loading: false }));
      };
      img.src = url;
    }

    return () => {
      isMounted = false;
    };
  }, [isPreviewOpen, previewIndex, previewImages]);

  // Handle keyboard navigation for the preview modal
  useEffect(() => {
    if (!isPreviewOpen) return;

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'ArrowLeft') navigatePreview('prev');
      else if (e.key === 'ArrowRight') navigatePreview('next');
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isPreviewOpen, navigatePreview]);


  const handleClientDownload = async (e: React.MouseEvent, url: string, filename: string) => {
    e.stopPropagation();
    try {
      const response = await fetch(url);
      const blob = await response.blob();
      const blobUrl = window.URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = blobUrl;
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      window.URL.revokeObjectURL(blobUrl);
    } catch (error) {
      console.error("Failed to download image", error);
      window.open(url, "_blank");
    }
  };

  function isVideoUrl(url: string): boolean {
    try {
      const pathname = new URL(url).pathname;
      const ext = pathname.split('.').pop()?.toLowerCase();
      return ['mp4', 'webm', 'mov', 'avi', 'mkv'].includes(ext || '');
    } catch {
      return false;
    }
  }

  function getFilenameFromUrl(url: string) {
    try {
      const pathname = new URL(url).pathname;
      const parts = pathname.split("/");
      const lastPart = parts[parts.length - 1];
      return decodeURIComponent(lastPart) || "download";
    } catch {
      return "download";
    }
  }

  function formatBytes(bytes: number, decimals = 1) {
    if (!+bytes) return '0 Bytes';
    const k = 1024;
    const dm = decimals < 0 ? 0 : decimals;
    const sizes = ['Bytes', 'KB', 'MB', 'GB', 'TB', 'PB', 'EB', 'ZB', 'YB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return `${parseFloat((bytes / Math.pow(k, i)).toFixed(dm))} ${sizes[i]}`;
  }

  function getStatusBadgeClasses(status: string) {
    const s = status.toLowerCase();
    if (s === "success" || s === "completed") {
      return "bg-teal-100 text-teal-800 border-teal-200";
    }
    if (s === "failed" || s === "failure") {
      return "bg-red-100 text-red-800 border-red-200";
    }
    if (s === "processing") {
      return "bg-purple-100 text-purple-800 border-purple-200";
    }
    if (s === "queued") {
      return "bg-gray-100 text-gray-800 border-gray-200";
    }
    return "bg-gray-100 text-gray-800 border-gray-200"; // fallback
  }

  return (
    <>
      <Dialog open={open} onOpenChange={onOpenChange}>
        {/* Width increased from max-w-4xl to max-w-6xl for a wider modal experience */}
        <DialogContent className="max-w-[95vw] md:max-w-6xl max-h-[90vh] flex flex-col p-6">
          <DialogHeader className="flex-none mb-6 pr-8">
          <div className="flex items-start justify-between">
            <div>
              <DialogTitle className="text-xl font-bold truncate pr-4">{name}</DialogTitle>
              <div className="text-sm text-gray-500 mt-1 space-x-2">
                <span className="font-medium text-gray-700">{pipeline}</span>
                <span>&bull;</span>
                <span>{createdAt ? format(new Date(createdAt), "PP pp") : "—"}</span>
              </div>
            </div>
            <div className={`px-3 py-1 text-xs font-medium rounded-full border flex-none capitalize mt-1 ${getStatusBadgeClasses(overallStatus)}`}>
              {overallStatus}
            </div>
          </div>
        </DialogHeader>

        <div className="flex-1 overflow-y-auto pr-2 min-h-0">
          {/* Row Results Table */}
          <div className="border border-gray-200 rounded-lg overflow-hidden shrink-0">
            <Table>
              <TableHeader className="bg-gray-50 sticky top-0 z-10">
                <TableRow>
                  <TableHead className="w-16">Row</TableHead>
                  <TableHead className="w-64">Directory</TableHead>
                  <TableHead>Result Files</TableHead>
                  <TableHead className="text-right w-32">Download All</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {isLoading && sortedRows.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={4} className="h-32 text-center text-sm text-gray-500">
                      Loading batch details...
                    </TableCell>
                  </TableRow>
                ) : sortedRows.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={4} className="h-32 text-center text-sm text-gray-500">
                      {isProcessing ? "Waiting for row results to arrive..." : "No row results available for this batch."}
                    </TableCell>
                  </TableRow>
                ) : (
                  sortedRows.map((row) => (
                    <TableRow key={row.id}>
                      <TableCell className="font-medium text-gray-900 align-top pt-4">
                        {row.row_index}
                      </TableCell>
                      <TableCell className="text-gray-600 align-top pt-4 break-all">
                        {row.directory_name || <span className="text-gray-400 italic">None</span>}
                      </TableCell>
                      <TableCell className="align-top pt-4">
                        {row.output_urls?.length > 0 ? (
                          <div className="grid grid-cols-2 lg:grid-cols-4 xl:grid-cols-5 gap-3">
                            {row.output_urls.map((out, idx) => {
                              const filename = getFilenameFromUrl(out.url);
                              return (
                                <div key={idx} className="group relative border border-gray-200 rounded-md overflow-hidden bg-gray-100 aspect-square flex items-center justify-center">
                                  {isVideoUrl(out.url) ? (
                                    <>
                                      <video
                                        src={out.url}
                                        title={filename}
                                        muted
                                        preload="metadata"
                                        className="w-full h-full object-cover cursor-zoom-in transition-opacity hover:opacity-85"
                                        onClick={(e) => {
                                          e.stopPropagation();
                                          const rowUrls = row.output_urls.map((o) => o.url);
                                          setPreviewImages(rowUrls);
                                          setPreviewIndex(idx);
                                        }}
                                      />
                                      <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                        <div className="bg-black/40 rounded-full p-2">
                                          <Play className="w-5 h-5 text-white fill-white" />
                                        </div>
                                      </div>
                                    </>
                                  ) : (
                                    <>
                                      <img
                                        src={out.url}
                                        alt={filename}
                                        title={filename}
                                        loading="lazy"
                                        decoding="async"
                                        className="w-full h-full object-cover cursor-zoom-in transition-opacity hover:opacity-85"
                                        onClick={(e) => {
                                          e.stopPropagation();
                                          const rowUrls = row.output_urls.map((o) => o.url);
                                          setPreviewImages(rowUrls);
                                          setPreviewIndex(idx);
                                        }}
                                        onError={(e) => {
                                          (e.target as HTMLImageElement).style.display = 'none';
                                          if (e.target && (e.target as HTMLElement).nextSibling) {
                                            ((e.target as HTMLElement).nextSibling as HTMLElement).style.display = 'flex';
                                          }
                                        }}
                                      />
                                      {/* Fallback layout for non-image files */}
                                      <div className="hidden absolute inset-0 flex-col items-center justify-center bg-gray-50 text-gray-400">
                                        <FileIcon className="w-8 h-8 mb-2" />
                                        <span className="text-[10px] w-full px-2 truncate text-center">{filename}</span>
                                      </div>
                                    </>
                                  )}

                                  <button
                                    onClick={(e) => handleClientDownload(e, out.url, filename)}
                                    className="absolute bottom-1 right-1 bg-white hover:bg-gray-100 text-gray-700 hover:text-black p-1.5 rounded-md shadow-md opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center border border-gray-200"
                                    title={`Download ${filename}`}
                                  >
                                    <Download className="w-4 h-4" />
                                  </button>
                                </div>
                              );
                            })}
                          </div>
                        ) : (
                          <span className="text-sm text-gray-400">—</span>
                        )}
                      </TableCell>
                      <TableCell className="text-right align-top pt-4">
                        {row.row_archive_url ? (
                          <Button
                            variant="ghost"
                            size="sm"
                            asChild
                            className="text-gray-600 hover:text-gray-900"
                            onClick={(e) => e.stopPropagation()}
                          >
                            <a href={row.row_archive_url} target="_blank" rel="noopener noreferrer">
                              <Archive className="w-4 h-4 mr-1.5" />
                              Zip
                            </a>
                          </Button>
                        ) : (
                          <span className="text-sm text-gray-400 pr-4">—</span>
                        )}
                      </TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </div>
        </div>

        {/* Footer */}
        {archiveUrl && (
          <div className="flex-none pt-4 mt-2 border-t flex justify-end">
            <Button asChild className="bg-purple-600 hover:bg-purple-700 text-white">
              <a href={archiveUrl} target="_blank" rel="noopener noreferrer" onClick={(e) => e.stopPropagation()}>
                <Download className="w-4 h-4 mr-2" />
                Download Full Batch Archive
              </a>
            </Button>
          </div>
        )}
      </DialogContent>
      </Dialog>

      {/* Image Preview Modal */}
      <Dialog open={isPreviewOpen} onOpenChange={(open) => !open && setPreviewImages([])}>
        <DialogContent 
          className="w-[95vw] md:w-[90vw] !max-w-[75rem] h-[85vh] p-0 flex flex-col md:flex-row bg-white border border-gray-200 shadow-2xl overflow-hidden group rounded-xl"
          showCloseButton={false}
        >
          <DialogTitle className="sr-only">Media Preview</DialogTitle>
          {/* Custom Close Button */}
          <button 
            onClick={() => setPreviewImages([])}
            className="absolute top-4 right-4 z-50 p-2 bg-white/80 backdrop-blur hover:bg-gray-100 rounded-full text-gray-800 transition-colors border border-gray-200 shadow-sm"
          >
            <X className="w-5 h-5" />
          </button>

          {previewImages.length > 0 && (
